// Filtra eventos de Evolution API (MESSAGES_UPSERT), separa audios de texto
const body = $json.body ?? $json;
const data = body.data;

// Ignorar si no hay datos o si el mensaje lo enviamos nosotros
if (!data || !data.key || data.key.fromMe) {
  return [];
}

// Ignorar mensajes de grupos (para no procesar el propio grupo de aviso)
if (String(data.key.remoteJid).endsWith('@g.us')) {
  return [];
}

const msg = data.message || {};
const isAudio = !!(msg.audioMessage || msg.pttMessage);
const text = msg.conversation
  || msg.extendedTextMessage?.text
  || '';

// Si no es audio y no hay texto (imagen, sticker, ubicación, etc.), ignorar
if (!isAudio && !text.trim()) {
  return [];
}

return [{
  json: {
    sessionId: data.key.remoteJid,
    number: String(data.key.remoteJid).split('@')[0],
    text: text.trim(),
    instance: body.instance,
    pushName: data.pushName || '',
    isAudio
  }
}];

// Deja pasar solo si el mensaje es un audio
if (!$json.isAudio) return [];
return [{ json: $json }];

// Deja pasar solo si el mensaje es texto (no audio)
if ($json.isAudio) return [];
return [{ json: $json }];

